#include <iostream>
#include <string>
#include <vector>

class Student {
private:
    std::string name;
    short id; 

public:
    static short totalStudents; 

    Student(std::string n, int i) : name(n) {
        id = i;
        totalStudents++;
    }

    static short getTotalStudents() {
        return totalStudents;
    }

    short getId() const { return id; }
};

short Student::totalStudents = 0;

int main() {
    std::cout << "Initial total students: " << Student::getTotalStudents() << '\n';

    Student s1("Alice", 101);
    std::cout << "After s1: " << Student::getTotalStudents() << '\n';

    Student s2("Bob", 102);
    Student s3("Charlie", 103);
    std::cout << "After s2, s3: " << Student::getTotalStudents() << '\n';

    Student s_trunc("TruncatedID", 40000);
    std::cout << "Student s_trunc created with ID 40000. Stored ID: " << s_trunc.getId() << '\n';
    std::cout << "After s_trunc: " << Student::getTotalStudents() << '\n';

    Student s4("David", 104);
    Student s5("Eve", 105);
    std::cout << "After s4, s5: " << Student::getTotalStudents() << '\n';

    return 0;
}
